const { app } = require('@azure/functions');
const { exec } = require('child_process');
const path = require('path');
const fs = require('fs').promises;
const crypto = require('crypto');

const ALLOWED_INPUT_FORMATS = ['.doc', '.docx', '.odt', '.rtf', '.txt', '.xls', '.xlsx', '.ods', '.ppt', '.pptx', '.odp'];
const ALLOWED_OUTPUT_FORMATS = ['pdf', 'docx', 'odt', 'txt', 'xlsx', 'ods', 'pptx', 'odp', 'html'];
const MAX_FILENAME_LENGTH = 255;
const CONVERSION_TIMEOUT = 60000;
const TEMP_DIR = process.env.TEMP_DIR || '/tmp/conversions';

function sanitizeFilename(filename) {
    if (!filename || typeof filename !== 'string') {
        throw new Error('Invalid filename');
    }
    
    if (filename.length > MAX_FILENAME_LENGTH) {
        throw new Error('Filename too long');
    }
    
    const normalized = path.normalize(filename).replace(/^(\.\.(\/|\\|$))+/, '');
    const basename = path.basename(normalized);
    
    if (basename !== normalized || basename.includes('..') || /[<>:"|?*\x00-\x1f]/g.test(basename)) {
        throw new Error('Invalid filename characters or path traversal detected');
    }
    
    return basename;
}

function validateOutputFormat(format) {
    if (!format || typeof format !== 'string') {
        throw new Error('Invalid output format');
    }
    
    const normalizedFormat = format.toLowerCase().trim();
    
    if (!ALLOWED_OUTPUT_FORMATS.includes(normalizedFormat)) {
        throw new Error(`Output format not allowed. Allowed formats: ${ALLOWED_OUTPUT_FORMATS.join(', ')}`);
    }
    
    return normalizedFormat;
}

function validateInputFormat(filename) {
    const ext = path.extname(filename).toLowerCase();
    
    if (!ALLOWED_INPUT_FORMATS.includes(ext)) {
        throw new Error(`Input format not allowed. Allowed formats: ${ALLOWED_INPUT_FORMATS.join(', ')}`);
    }
    
    return ext;
}

async function ensureTempDirectory() {
    try {
        await fs.access(TEMP_DIR);
    } catch {
        await fs.mkdir(TEMP_DIR, { recursive: true, mode: 0o700 });
    }
}

async function cleanupFiles(...filePaths) {
    for (const filePath of filePaths) {
        try {
            await fs.unlink(filePath);
        } catch (err) {
            // Ignore cleanup errors
        }
    }
}

function executeLibreOffice(inputPath, outputDir, outputFormat) {
    return new Promise((resolve, reject) => {
        const args = [
            '--headless',
            '--invisible',
            '--nodefault',
            '--nofirststartwizard',
            '--nolockcheck',
            '--nologo',
            '--norestore',
            '--convert-to',
            outputFormat,
            '--outdir',
            outputDir,
            inputPath
        ];
        
        const command = 'soffice';
        const fullCommand = `${command} ${args.map(arg => {
            if (arg === inputPath || arg === outputDir) {
                return `"${arg.replace(/"/g, '\\"')}"`;
            }
            return arg;
        }).join(' ')}`;
        
        exec(fullCommand, {
            timeout: CONVERSION_TIMEOUT,
            maxBuffer: 10 * 1024 * 1024,
            env: {
                HOME: TEMP_DIR,
                PATH: process.env.PATH
            }
        }, (error, stdout, stderr) => {
            if (error) {
                reject(new Error(`Conversion failed: ${error.message}`));
                return;
            }
            resolve({ stdout, stderr });
        });
    });
}

app.http('convertDocument', {
    methods: ['POST'],
    authLevel: 'function',
    handler: async (request, context) => {
        let inputFilePath = null;
        let outputFilePath = null;
        
        try {
            const body = await request.json();
            
            if (!body || typeof body !== 'object') {
                return {
                    status: 400,
                    jsonBody: { error: 'Invalid request body' }
                };
            }
            
            const { inputFilename, outputFormat, fileContent } = body;
            
            const sanitizedFilename = sanitizeFilename(inputFilename);
            validateInputFormat(sanitizedFilename);
            const validatedOutputFormat = validateOutputFormat(outputFormat);
            
            if (!fileContent || typeof fileContent !== 'string') {
                return {
                    status: 400,
                    jsonBody: { error: 'File content is required as base64 string' }
                };
            }
            
            await ensureTempDirectory();
            
            const sessionId = crypto.randomBytes(16).toString('hex');
            const sessionDir = path.join(TEMP_DIR, sessionId);
            await fs.mkdir(sessionDir, { mode: 0o700 });
            
            inputFilePath = path.join(sessionDir, sanitizedFilename);
            
            const fileBuffer = Buffer.from(fileContent, 'base64');
            
            if (fileBuffer.length > 50 * 1024 * 1024) {
                await fs.rmdir(sessionDir, { recursive: true });
                return {
                    status: 400,
                    jsonBody: { error: 'File size exceeds 50MB limit' }
                };
            }
            
            await fs.writeFile(inputFilePath, fileBuffer, { mode: 0o600 });
            
            await executeLibreOffice(inputFilePath, sessionDir, validatedOutputFormat);
            
            const baseName = path.parse(sanitizedFilename).name;
            outputFilePath = path.join(sessionDir, `${baseName}.${validatedOutputFormat}`);
            
            const convertedFile = await fs.readFile(outputFilePath);
            const base64Output = convertedFile.toString('base64');
            
            await fs.rmdir(sessionDir, { recursive: true });
            
            return {
                status: 200,
                headers: {
                    'Content-Type': 'application/json'
                },
                jsonBody: {
                    success: true,
                    outputFilename: `${baseName}.${validatedOutputFormat}`,
                    fileContent: base64Output,
                    size: convertedFile.length
                }
            };
            
        } catch (error) {
            if (inputFilePath || outputFilePath) {
                const sessionDir = path.dirname(inputFilePath || outputFilePath);
                try {
                    await fs.rmdir(sessionDir, { recursive: true });
                } catch {}
            }
            
            context.error('Conversion error:', error.message);
            
            return {
                status: 400,
                jsonBody: { 
                    error: 'Document conversion failed',
                    message: error.message 
                }
            };
        }
    }
});